  ('locality-e0adf6cd-moex-00090', 'locality-e0adf6cd', 'locality-e0adf6cd-moex-113-3082b5f1', 'sub-locality-e0adf6cd-06', NULL, 'single_choice', '關於訴願管轄之敘述，下列何者正確？', '["不服公平交易委員會之行政處分者，應以行政院為訴願管轄機關", "汽車燃料使用費之徵收，應以交通部為訴願管轄機關", "同一直轄市主管之數個高級中學成立聯合甄審委員會，對於教師新聘事項進行評審，以教育部 為訴願管轄機關", "有關國民年金保險事項所為之核定，以勞動部勞工保險局為訴願管轄機關"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:11+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "c6e2c8da67de", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "308", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "教育行政"}'::jsonb, NULL),
