  ('locality-e0adf6cd-moex-00092', 'locality-e0adf6cd', 'locality-e0adf6cd-moex-113-3082b5f1', 'sub-locality-e0adf6cd-06', NULL, 'single_choice', '甲原經乙市政府社會局核定為低收入戶並按月領有低收入生活扶助，嗣後社會局查知甲已將戶籍 遷出乙市，乃以A函通知甲自即日起廢止其低收入戶資格並停止發給生活扶助。甲不服，循序提 起訴願及撤銷訴訟，經行政法院撤銷A函，但社會局僅繼續發給確定判決後之生活扶助。甲依法 應如何救濟？', '["提起再審", "提起課予義務訴訟", "請求行政訴訟強制執行", "提起一般給付訴訟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:11+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "c6e2c8da67de", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "308", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "教育行政"}'::jsonb, NULL),
  ('locality-e0adf6cd-moex-00093', 'locality-e0adf6cd', 'locality-e0adf6cd-moex-113-3082b5f1', 'sub-locality-e0adf6cd-06', NULL, 'single_choice', '關於行政裁量之敘述，下列何者錯誤？', '["法院在認定裁量怠惰時，應視該被指摘漏未考量之因素在個案中之權重，而為決定", "行政機關為裁量時，若違反平等原則，即構成裁量瑕疵", "行政機關以狀態責任人為裁罰對象時，應斟酌其有無事實支配管領力、能否有效為停止使用等 情事", "行政機關於個案行使裁量權時，作成不同於裁量基準之決定，即構成裁量濫用"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:11+00:00", "source_pdf_sha1": "cc84cfeb0f66", "answer_pdf_sha1": "c6e2c8da67de", "source_family": "moex-gov-tw", "moex": {"exam_code": "113200", "c": "308", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "113", "exam_name": "113年特種考試地方政府公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "教育行政"}'::jsonb, NULL),
